#!/usr/bin/env python3
from __future__ import annotations

import base64
import gzip
import json
from pathlib import Path

ROOT = Path(__file__).resolve().parents[1]
TARGET = ROOT / "data" / "generated_units" / "quimica-i" / "unit-01.json"
PAYLOAD = """"""


def main() -> int:
    raw = gzip.decompress(base64.b64decode(PAYLOAD))
    data = json.loads(raw.decode("utf-8"))
    assert data["schema_version"] == "2.0"
    assert data["subject_id"] == "quimica-i"
    assert data["unit"] == 1
    assert data["weeks"] == [1, 2, 3]
    assert data["estimated_hours"] == 24
    assert len(data["theory_sections"]) >= 4
    assert all(len(section.get("paragraphs", [])) >= 4 for section in data["theory_sections"])
    assert len(data["worked_examples"]) >= 2
    assert len(data["self_assessment"]) >= 8
    assert len(data["sources"]) >= 5
    TARGET.write_text(json.dumps(data, ensure_ascii=False, indent=2) + "\n", encoding="utf-8")
    print(f"Actualizada {TARGET.relative_to(ROOT)}")
    return 0


if __name__ == "__main__":
    raise SystemExit(main())
